'use client'

import { createContext, use } from 'react'
import type { CSSProperties } from 'react'
import styles from './logo-marquee.module.css'

export interface Logo {
  id: string
  title: string
  path: string
}

interface AnimationConfig {
  duration: number
  stagger: number
}

const DEFAULT_CONFIG: AnimationConfig = {
  duration: 20,
  stagger: 0.6,
}

const MarqueeContext = createContext<AnimationConfig & { columns: number }>(
  { ...DEFAULT_CONFIG, columns: 4 }
)

const ITEMS_PER_COLUMN = 4 // keyframe %s in the CSS module are tuned for 4

const LAYERS = [
  { fill: 'red', u: 0 },
  { fill: 'yellow', u: 1 },
  { fill: '#1061ff', u: 2 },
  { fill: 'currentColor', u: 3 },
] as const

function MarqueeTrack({ logos, colIndex }: { logos: Logo[]; colIndex: number }) {
  const { stagger, columns } = use(MarqueeContext)
  const baseDelay = Math.sin((colIndex / columns) * (Math.PI / 4)) * stagger

  return (
    <ul
      className={styles.list}
      style={
        {
          '--items': ITEMS_PER_COLUMN,
          '--base-delay': baseDelay,
        } as CSSProperties
      }
    >
      {logos.map((logo, i) => (
        <li
          key={logo.id}
          className={styles.item}
          style={{ '--i': i + 1 } as CSSProperties}
        >
          <svg
            role="img"
            viewBox="0 0 24 24"
            xmlns="http://www.w3.org/2000/svg"
            className={styles.svg}
          >
            <title>{logo.title}</title>
            {LAYERS.map(({ fill, u }) => (
              <path
                key={u}
                d={logo.path}
                fill={fill}
                className={styles.layer}
                style={{ '--u': u } as CSSProperties}
              />
            ))}
          </svg>
        </li>
      ))}
    </ul>
  )
}

export interface LogoMarqueeProps {
  logos?: Logo[]
  columns?: number
  config?: Partial<AnimationConfig>
}

export default function LogoMarquee({
  logos = DEFAULT_LOGOS,
  columns = 4,
  config,
}: LogoMarqueeProps = {}) {
  const mergedConfig = { ...DEFAULT_CONFIG, ...config, columns }

  const columnData = Array.from({ length: columns }, (_, col) =>
    logos.slice(col * ITEMS_PER_COLUMN, (col + 1) * ITEMS_PER_COLUMN)
  )

  return (
    <MarqueeContext value={mergedConfig}>
      <div
        className={styles.container}
        style={{ '--duration': mergedConfig.duration } as CSSProperties}
      >
        {columnData.map((column, colIndex) => (
          <MarqueeTrack key={colIndex} logos={column} colIndex={colIndex} />
        ))}
      </div>
    </MarqueeContext>
  )
}

